#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long X; scanf("%lld", &X);
        int r = X % 3;
        if (r == 0) printf("NORMAL\n");
        else if (r == 1) printf("HUGE\n");
        else printf("SMALL\n");
    }
    return 0;
}

