import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    for i in range(1, t+1):
        x = int(data[i])
        r = x % 3
        if r == 0:
            out.append('NORMAL')
        elif r == 1:
            out.append('HUGE')
        else:
            out.append('SMALL')
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

